class Solution {
    public double new21Game(int n, int k, int maxPts) {
        if (k == 0) return n >= 1 ? 1.0 : 0.0;
        double[] dp = new double[n + 1];
        for (int i = k; i <= Math.min(n, k + maxPts - 1); i++) {
            dp[i] = 1.0 / maxPts;
        }
        for (int i = k - 1; i >= 0; i--) {
            double sum = 0;
            for (int j = i + 1; j <= Math.min(i + maxPts, n); j++) {
                sum += dp[j];
            }
            dp[i] = sum / maxPts;
        }
        double res = 0;
        for (int i = 0; i <= n; i++) {
            res += dp[i];
        }
        return res;
    }
}
